var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"열흘 전","JPN":"10日前","ENG":"Ten days earlier","TWN":"十天前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>\\n이스트 시티, 코핀 컴퍼니 샤레이드 지부.","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>\\nイーストシティ、コフィンカンパニーシャレード支部","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>\\nEast City, Coffin Company Charade Branch.","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>\\n東城，科芬公司查雷德分部。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 그동안 다들 너무너무 고생 많았어!","JPN":"みんな、今まで本当にお疲れ様！","ENG":"All right, great job hanging in there, everyone!","TWN":"來吧，這段時間大家都辛苦了！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그럼~ 펠리세트, 라이카 두 사람의 퇴원식을 기념하면서 다 같이~!","JPN":"じゃあ、フェリセットとライカ、2人の退院を祝う意味で～","ENG":"And now, to celebrate Félicette and Laika finally being discharged...!","TWN":"那麼～為了紀念費莉塞特和萊卡兩人的出院儀式，大家一起～"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"건배!","JPN":"乾杯！","ENG":"Cheers!","TWN":"乾杯!"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……라고는 하지만 역시 샤레이드 지부에 저희뿐이라서 썰렁하네요.","JPN":"……とはいえ、やっぱりシャレード支部に私たちだけというのも寂しいですね。","ENG":"Though, with just us here at the Charade branch, it feels a bit empty.","TWN":"……雖然這麼說，但畢竟只有我們在查雷德分部，還是有點冷清啊。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하하, 그거야 어쩔 수 없잖아……?","JPN":"はは、それは仕方ないでしょ……？","ENG":"Haha, well, it can't be helped...","TWN":"哈哈，沒辦法了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"건틀렛 리그가 끝나자마자, 숨돌릴 틈 없이 커다란 사건들이 연달아 터져버렸으니까.","JPN":"ガントレットリーグが終わるや否や、一息つく間もなく大きな事件が連続で起きたんだから。","ENG":"Right after the Gauntlet League ended, one huge incident after another hit us without a break.","TWN":"聖鎧聯賽剛結束，接連不斷的大事件讓人喘不過氣來。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"바로 전날, 시상식까지 멀쩡하던 샤레이드 시니어가 살해되질 않나…….","JPN":"授賞式までピンピンしてたシャレードのシニアが翌朝死体で発見されたり……","ENG":"Just the day before, the Charade Senior was alive and well at the award ceremony... then suddenly he's murdered...","TWN":"就在前一天，原本在頒獎典禮上還好好的查雷德Senior被殺了。"},"stage":{"bg":"CHARADE2_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하늘에서 커다란 눈이 나타나더니, 갑자기 사람들이 공중으로 끌려가질 않나…….","JPN":"空に大きな目が現れて、突然人々が宙に浮かされたり……","ENG":"Then a giant eye appeared in the sky, and people started getting pulled up into the air...","TWN":"天空中突然出現了一隻巨大的眼睛，接著人們就被吸到了空中。"},"stage":{"bg":"MS_1203","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"게다가 이번에는 관리 경계 구역에 커다란 우주선이 나타났다면서?","JPN":"しかも今度は管理警戒区域に巨大宇宙船が現れたでしょう？","ENG":"And now there's talk of a massive spaceship showing up in the perimeter zone?","TWN":"而且這次在管理警戒區出現了一艘巨大的太空船？"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"대체 세상이 어떻게 돌아가는 건지, 참…….","JPN":"いったい世の中どうなってるのか、まったく……","ENG":"Seriously, what is even happening in the world anymore...?","TWN":"到底這個世界是怎麼回事，真是……"},"stage":{"bg":"MS_1407","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"뭐, 아무튼 사건들을 수습하기 위해, 사장님께서 로터스에 남기로 결정하셨잖아?","JPN":"まあ、とにかく事件の収拾のために社長がロータスに残ることになったじゃない。","ENG":"Anyway, to deal with all that, Boss decided to stay behind in Lotus, right?","TWN":"總之，為了處理這些事件，老闆決定留在洛德斯，對吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래서 두 사람의 퇴원을 기념해서, 일상으로 돌아온 걸 축하하는 자리를 준비해 봤어.","JPN":"だから2人の退院を記念して、日常に戻ったことを祝う場を作ってみたの。","ENG":"So I thought we'd take this chance to celebrate your discharge... and your return to normal life.","TWN":"所以為了紀念兩人出院，準備了一個慶祝回歸日常的場合。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"일상이라……. 그리운 단어네요.","JPN":"日常……懐かしい響きです。","ENG":"\\"Normal life\\"... It's been a long time since I've heard those words.","TWN":"日常啊……真是懷念的詞語呢。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그동안 이런저런 사건에 휘말려서 정신없이 달려오긴 했죠.","JPN":"しばらくの間、色んな事件に巻き込まれてがむしゃらに走ってきましたからね。","ENG":"We really have been rushing nonstop, getting caught up in one incident after another.","TWN":"這段時間捲入了各種事件，忙得不可開交。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"후후, 그러게.","JPN":"ふふ、そうだね。","ENG":"Haha... yeah, it's been a wild ride.","TWN":"呵呵，是啊。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"기억나? 비록 시작은 불법 침입이었지만, 이곳에서 카나리아 스쿼드의 꿈이 시작됐다구?","JPN":"覚えてる？　最初は違法侵入だったけど、ここでカナリア・スクワッドの夢が始まったんだよ？","ENG":"Remember? We technically broke in here at the start, but this is where the dream of the Canary Squad began.","TWN":"還記得嗎？雖然開始是非法入侵，但金絲雀小隊的夢想就是從這裡開始的喔？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이제 그 꿈을 이루었으니까, 또다시 새로운 목표를 향해 정진할 때가 아닐까?","JPN":"もうその夢も叶ったことだし、また新しい目標に向かって精進する時じゃないかな？","ENG":"Now that we've made that dream come true... maybe it's time to aim for something new.","TWN":"既然已經實現了那個夢想，是時候再次朝著新的目標前進了吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……꿈?","JPN":"……夢？","ENG":"...A dream?","TWN":"……夢？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오, 꿈도 크다.","JPN":"おお、夢がデカいな。","ENG":"Wow, you got big dreams.","TWN":"噢，你的夢想真遠大。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래도 응원해 줄게. 여기 꼬맹이도 꿈이 참 허무맹랑하걸랑.","JPN":"でも応援するよ。こいつもとんでもない夢を持ってるしな。","ENG":"But I'll root for ya. You see, that kid over there also has big dreams.","TWN":"不過我還是會替你加油，我們這個小鬼也有遠大的夢想喔。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"쓸데없는 소리 하지 마세요, 라이카.","JPN":"余計なことを言わないでよ、ライカ。","ENG":"Stop the unnecessary talk, Laika.","TWN":"別說那些有的沒的，萊卡。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"정■요? 어■ 꿈인데■?","JPN":"本■ですか？　どん■夢な■■すか？","ENG":"Re■lly? Wh■t ■ind of drea■s?","TWN":"真■嗎？什■夢■？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"듣고 놀라지나 마시라~ 무려 건틀렛 챔피언이라구~","JPN":"聞いて驚くなよ～？　ガントレットチャンピオンだってさ～","ENG":"Well, don't be shocked! She wants to be the Gauntlet champion!","TWN":"你聽到不要嚇到喔～她的夢想是聖鎧冠軍～"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……몇 번을 말해요. 챔피언이 아니라 결승 진출이라구요.","JPN":"……何度も言ったでしょう？　チャンピオンじゃなくて、決勝進出です。","ENG":"...How many times do I have to tell you? It's not about becoming a champion, but going to the finals.","TWN":"……我說過多少次，不是冠軍，是打入決賽。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"남의 목표를 술자리 우스갯소리로 쓰지 마세요. 불쾌해요.","JPN":"人の目標を飲み会の笑いのネタにしないでほしいわ。不愉快よ。","ENG":"Please stop using someone's dream as your joke. It's rude.","TWN":"不要把別人的夢想當成餐桌上的笑話，感覺很差欸。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"■승 진■!","JPN":"■勝進■！","ENG":"T■ t■e fi■als!","TWN":"■晉級■！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_MAIN_NPC_SHADOW","text":{"KOREA":"왠지 ■슴이 두근 거■는 ■어■■! 멋■요!","JPN":"なんだか■キドキ■る単■で■■！　素■です！","ENG":"Just h■aring th■se words m■kes my hea■t rac■! It's awes■me!","TWN":"不知道為什麼，感覺這個夢想很讓人心潮澎湃呢！很帥！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……어?","JPN":"……あれ？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"음? 표정이 왜 그래, 펠리세트?","JPN":"うん？　どうしたの、フェリセット？","ENG":"Hmm? What's with that look, Félicette?","TWN":"嗯？你那是什麼表情，費莉塞特？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아, 아니요…….","JPN":"い、いいえ……","ENG":"Ah, it's nothing...","TWN":"不是的……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"왠지 전에도 이런 비슷한 대화를 나눴던 것 같은 기분이 들어서…….","JPN":"なんか、前にも似たような会話をした気がして……","ENG":"It just feels like... we've had this exact conversation before.","TWN":"總覺得之前好像也有過類似的對話。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 그게? 데자뷰?","JPN":"なにそれ？　デジャヴ？","ENG":"Huh? What, like deja vu?","TWN":"這是什麼？既視感？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그게 아니면… 요 꼬마 녀석! 혹시 손에 들고 있는 거 보리차가 아니라 맥주 아니야?","JPN":"もしかして……この子ったら！　手に持ってるそれ、麦茶じゃなくてビールなんじゃないの？","ENG":"Or maybe... hey, you little rascal! That's not tea in your hand, is it? Is that beer?!","TWN":"不是那樣的話……你這小傢伙！你手裡拿的是啤酒而不是麥茶吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아니에요! 보리차라고요, 보리차!","JPN":"違います！　麦茶ですよ、麦茶！","ENG":"It is not! It's tea! I swear!","TWN":"不是的！是麥茶，麥茶！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아하하! 간지러워요, 스키너! 항복이에요, 항복! 항복!","JPN":"あはは！　くすぐったいです、スキナー！　降参！　降参！","ENG":"Ahahaha! Stop it, Skinner! That tickles! I surrender! I surrender!","TWN":"啊哈哈！好癢啊，史金納！我投降，我投降！投降！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"와하하! 이런 좋은 날 보리차면 어떻고 맥주면 어떤가! 즐기면 그만이지!","JPN":"わはは！　こんなめでたい日、麦茶でもビールでも構わんだろう！","ENG":"Haha! On a day like this, who cares if it's tea or beer? Just enjoy it!","TWN":"哇哈哈！這麼好的日子，喝麥茶也好，喝啤酒也好！只要開心就行了！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"무슨 말씀이세요, 햄스워스 씨.","JPN":"何を言ってるんですか、ヘムズワースさん。","ENG":"What are you talking about, Helmsworth?","TWN":"你在說什麼啊，漢姆沃斯先生。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"펠리세트는 아직 미성년자거든요?","JPN":"フェリセットはまだ未成年ですよ？","ENG":"Félicette's still underage, you know.","TWN":"費莉塞特還未成年呢！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"어쨌든 펠리세트, 라이카! 두 사람 모두 고생 많았다!","JPN":"とにかくフェリセット、ライカ！　2人ともご苦労さん！","ENG":"Anyway, Félicette, Laika! You both did an amazing job!","TWN":"不管怎樣，費莉塞特，萊卡！你們兩個都辛苦了！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"오늘은 이 햄스워스 님이 전부 살 테니까, 다들 마셔! 마시라구……!","JPN":"今日はこのヘムズワースの奢りだ、思う存分飲め！　飲むんだ……！","ENG":"Tonight, it's all on me! So drink up! Drink...!","TWN":"今天由我漢姆沃斯請客，大家盡情喝吧！喝起來！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"와하하하하하……!","JPN":"わははははは……！","ENG":"Wah hah hah hah!","TWN":"哇哈哈哈哈哈！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아니, 햄스워스 씨는 좀 그만 마셔야 할 것 같은데…….","JPN":"いや、ヘムズワースさんはもう十分飲んでいる気が……","ENG":"Umm... Helmsworth, maybe you should stop drinking now...","TWN":"不，漢姆沃斯先生，你該少喝點了……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"스키너, 저 수염 난 할아버지가 왜 샤레이드에 남아 있는 거예요?","JPN":"スキナー、あの髭のおじいさんはなぜシャレードにまだ居るんですか？","ENG":"Skinner, why is that bearded old man still here in Charade?","TWN":"史金納，那個留鬍子的老爺爺為什麼還留在查雷德？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"리그가 끝나면, 그라운드 원으로 돌아간다고 하지 않았어요?","JPN":"リーグが終わったらグラウンド・ワンに帰るんじゃなかったですか？","ENG":"Didn't he say he'd return to Ground One once the league was over?","TWN":"聯賽結束後，不是說要回到G1嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"아하하, 그건 말이지…….","JPN":"あはは、それはね……","ENG":"Ahaha, well, here's the thing...","TWN":"啊哈哈，其實是這樣的……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너희들이 리그에서 우승하는 걸 보고, 햄스워스 씨가 건틀렛 리그에 완전히 빠져버렸거든.","JPN":"あなたたちがリーグで優勝するのを見て、ヘムズワースさんったらガントレットリーグにはまっちゃったのよ。","ENG":"After seeing you guys win the league, Helmsworth got completely hooked on the Gauntlet League.","TWN":"看到你們在聯賽中獲勝，海姆斯沃思先生完全沉迷于聖鎧聯賽了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래서 당분간 카나리아 스쿼드의 전문 정비사로 계약을 맺게 되었어.","JPN":"それでしばらく、カナリア・スクワッドの専門整備士として契約することになったって話。","ENG":"So now he's officially signed on as the Canary Squad's exclusive mechanic.","TWN":"所以暫時與金絲雀小隊簽訂了專業維修技師的合約。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네? 정말이요?","JPN":"え？　本当ですか？","ENG":"Wait, no way, really?!","TWN":"啊？真的嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"하하! 이 쪼끄만 치와와 녀석! 설마, 이 몸이 싫은 게냐!","JPN":"はは！　このチワワみたいなやつめ！　ワシが気に入らんのか！","ENG":"Haha! You tiny little chihuahua! What, you don't want me around?!","TWN":"哈哈！這只小小的吉娃娃！難道，是討厭本尊嗎！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"햄스워스 공방이라고 하면, 그라운드원에서도 꽤 알아주는 공방이란 말이다!","JPN":"ヘムズワース工房といえば、グラウンド・ワンでも指折りの工房だぞ！","ENG":"Helmsworth Workshop is a big deal, even back in Ground One, you know!","TWN":"說到漢姆沃斯工坊，在G1也是相當有名的工坊啊！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"공방 제자 녀석들도 날 따라오려면 아직 10년은 일러!","JPN":"工房の弟子たちもワシに追いつくにはまだ10年は早いわ！","ENG":"The apprentices at the shop? They're still ten years too early to catch up to me!","TWN":"工坊的那些徒弟們要想趕上我，還早10年呢！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으아악! 들러붙지 마세요! 이 영감탱이!","JPN":"うわあ！　くっつかないでください！　こっのジジイ！","ENG":"Aaaah! Don't cling to me, you old drunk!","TWN":"啊啊啊！別纏著我！你這個老頭！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"술 냄새 난다니까! 빨리 안 놓으면, 콱 물어버릴 거예요……!","JPN":"酒臭いですよ！　早く放さないと噛みますから……！","ENG":"You reek of booze! If you don't let go right now, I swear I'll bite you...!","TWN":"我說有酒味啊！再不放手，我就咬你了……！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카! 빨리 와서 이 고주망태 할아범 좀 어떻게 해 봐요!","JPN":"ライカ！　早く来てこの酔っ払いをどうにかして！","ENG":"Laika! Hurry up and do something about this staggering old man!","TWN":"萊卡！快來看看這個醉醺醺的老頭子吧！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>쿠드랴프카, 들리나?</color>","JPN":"<color=#ff3636>クドリャフカ、聞こえるか？</color>","ENG":"<color=#ff3636>Kudryavka, do you hear me?</color>","TWN":"<color=#ff3636>庫德里亞夫卡，聽得到嗎？</color>"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>목표 지점에서 나타나는 현상을 관측, 연구하라.</color>","JPN":"<color=#ff3636>目標地点における現象を観測、研究せよ。</color>","ENG":"<color=#ff3636>Observe the phenomenon at the objective point, and research it.</color>","TWN":"<color=#ff3636>觀測並研究在目標地點出現的現象。</color>"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>반복한다.</color>","JPN":"<color=#ff3636>繰り返す。</color>","ENG":"<color=#ff3636>I repeat.</color>","TWN":"<color=#ff3636>重複一遍。</color>"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>목표 지점에서 나타나는 현상을…….</color>","JPN":"<color=#ff3636>目標地点における現象を……</color>","ENG":"<color=#ff3636>Observe the phenomenon at the objective point–</color>","TWN":"<color=#ff3636>在目標地點出現的現象。</color>"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"라이카? 갑자기 왜 그렇게 식은 땀을 흘려? 괜찮아?","JPN":"ライカ？　急にどうしたの？　冷や汗がすごいじゃない、大丈夫？","ENG":"Laika? You're suddenly sweating. Are you okay?","TWN":"萊卡？你怎麼突然出那麼多冷汗？沒事吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 왜 그래요?","JPN":"ライカ、どうしたの？","ENG":"Laika, what's wrong?","TWN":"萊卡，怎麼了？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"설마, 낮에 뉴스에서 봤던 그 우주선 때문에……?","JPN":"まさか、昼のニュースで見たあの宇宙船のせい……？","ENG":"Wait... is this because of that spaceship we saw on the news earlier today?","TWN":"難道，是因為白天在新聞上看到的那艘太空船？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……아하하! 별거 아니라고!","JPN":"……あはは！　なんでもないよ！","ENG":"...Ahaha! It's nothing, really!","TWN":"……啊哈哈！沒什麼啦！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오랜만에 뱃속에 알코올이 들어가서 그런가? 약간 어지럽네.","JPN":"久ぶりにアルコールが入ったせいかな。ちょっとクラクラしちゃって。","ENG":"Guess it's just been too long since I've had a drink. I'm feeling a little dizzy.","TWN":"好久沒喝酒了，肚子裡有了酒精，感覺有點暈。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나 먼저 들어갈 테니까, 다들 신경쓰지 마!","JPN":"先に帰るから、みんな心配するなよ！","ENG":"I'll head in first. Don't worry about me!","TWN":"我先進去，大家不用擔心！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카…….","JPN":"ライカ……","ENG":"Laika...","TWN":"萊卡……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff…!*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이런, 제기랄……!","JPN":"ちくしょう……！","ENG":"Damn it...!","TWN":"該死……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래, 이 염병할 놈의 인생이 뭐 이렇지……!","JPN":"このくそったれの人生、結局こんな有様ってわけか……？","ENG":"Why does life always do this to me...?","TWN":"是啊，這該死的人生怎麼會這樣……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이제야 뭐 잘 풀리나 싶었는데, 또 베베 꼬여갖고……!","JPN":"やっと上手くいくようになったと思ったら、また無茶苦茶になって……！","ENG":"Just when it finally felt like things were turning around... now it's all tangled up again!","TWN":"好不容易才有點起色，又搞砸了……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"벌써 몇 년이나 지나버린 일이잖아…! 이제 좀 잊어버릴 때도 되지 않았냐고……?","JPN":"もう何年も前のことだぞ……！　いい加減忘れさせてくれよ、マジで……","ENG":"It's already been years...! Isn't it time I finally moved on...?","TWN":"這已經是好幾年前的事了……！現在該忘掉了吧……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니… 잊어버릴 리가 없지…….","JPN":"いや……忘れられるわけがない……","ENG":"No... There's no way I could forget...","TWN":"不……怎麼可能會忘記……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그때 봤던 광경… 그리고 그때 들었던 목소리……","JPN":"あの時見た光景……そしてあの時聞いた声……","ENG":"What I saw back then... and the voice I heard...","TWN":"那時看到的景象……還有那時聽到的聲音……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아직도 이렇게 생생한데 잊어버릴 리가 없잖아…….","JPN":"まだこんなにもはっきり思い出せるのに、忘れられるわけがない……","ENG":"It's all still so vivid, so how could I ever forget...?","TWN":"還這麼清晰，怎麼可能會忘記呢……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……라이카 양.","JPN":"……ライカ君。","ENG":"...Laika.","TWN":"……萊卡。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 경기에서 자네의 움직임을 보면서 한 가지 떠오른 게 있네만.","JPN":"今日の試合での君の動きを見て1つ思ったのだが。","ENG":"There is something that came to me while watching your movements today.","TWN":"在今天的比賽中，看到你的行動之後讓我想起一件事。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"응, 뭔데?","JPN":"うん、何？","ENG":"Yeah, what is it?","TWN":"嗯？什麼？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"혹시, 맨션에 대해 알고 있나?","JPN":"マンションについて知っているかね？","ENG":"Does the name Mansion ring a bell?","TWN":"你知道曼森嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐 그럭저럭. 우주에 나가려면 배워야 할 게 많았으니까.","JPN":"まぁ、ある程度はね。宇宙に出ていくには色々学ばないといけなかったから。","ENG":"More or less. I had to learn a lot of things to go out in space.","TWN":"略有耳聞。畢竟想要去宇宙，就要學很多東西。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"왜? 그쪽에 아는 사람이라도 있어?","JPN":"何？　そこに知り合いでもいるの？","ENG":"Why? Do you know anyone there?","TWN":"怎麼這麼問？曼森裡有你認識的人？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일단은. 안부 묻고 지낼 사이는 아니네만.","JPN":"まあね。近況を聞くほどの仲ではないのだが。","ENG":"I do, although we rarely talk.","TWN":"算是吧，但不是友好的關係。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 우주라…… 전에도 그런 말을 했었지?","JPN":"しかし宇宙か……以前もそのようなことを言っていたな？","ENG":"But space... I remember you mentioning it once.","TWN":"不過……你之前也有提到宇宙的事吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금이라면, 이야기를 들을 수 있을까?","JPN":"今なら、その話を聞いてもいいかね？","ENG":"Would it be all right to hear more about it now?","TWN":"現在可以說給我聽了嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……글쎄. 잘 설명할 수 있으려나. 머리가 좋은 편은 아니라.","JPN":"……どうかな。うまく説明できるかどうか。そんなに頭がいい方じゃないから。","ENG":"...I dunno if I can even explain it well to you. I'm not the sharpest tool in the shed, you see.","TWN":"……這個嘛，我不確定我能說得清楚嗎？因為我的腦袋不太好。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"빌어먹게 자랑스러운 조국이 우릴 그 지옥으로 던져 넣은 이유는 하나였어.","JPN":"クソ誇らしい祖国が、私たちをあの地獄に放り込んだ理由はたった1つだった。","ENG":"But there was only one reason why my obnoxiously proud country threw us into that hell-hole.","TWN":"可惡的是，我以我的國家為榮，他們卻把我們扔在那裡。而理由只是因為……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>목표 지점에서 나타나는 현상을 관측, 연구하라.</color>","JPN":"<color=#ffd34c>目標地点における現象を観測、研究せよ。</color>","ENG":"<color=#ffd34c>Observe the phenomenon at the objective point, and research it.</color>","TWN":"<color=#ffd34c>觀測並研究在目的地出現的現象。</color>"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 탐사단의 대부분이 개죽음을 당하면서 간신히 목표 지점까지 도달했지.","JPN":"そして探索チームのほとんどが無意味に命を落としながら、やっと目標地点までたどり着いた。","ENG":"Most of the expedition crew's lives had been lost in vain when we reached that point.","TWN":"結果在白白犧牲好多探索隊員的性命後，好不容易才抵達目的地。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"거기서 우리가 본 건…….","JPN":"そこで私たちが見たのは……","ENG":"And what we saw there was...","TWN":"而我們在那裡看到的……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……틀림없이 <color=#ffd34c>빛</color>이었어.","JPN":"……間違いなく<color=#ffd34c>光</color>だった。","ENG":"It was definitely <color=#ffd34c>light</color>.","TWN":"……那一定是<color=#ffd34c>光</color>。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"빛이라고?","JPN":"光？","ENG":"Light?","TWN":"你說光？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래, 달의 뒷면에서 어떤 빛이 뿜어져 나오고 있었어.","JPN":"そう。月の裏側から、何かが光っていた。","ENG":"Yeah. A light was radiating from the dark side of the moon.","TWN":"是的，月亮的背面有一道光芒在閃耀。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 빛은 작지만, 마치 심장이 뛰는 것처럼 일정하게 점멸하고 있었고…….","JPN":"小さいけど、まるで心臓が脈打つように一定の間隔で点滅していて……","ENG":"It was small, but it pulsed... steady, like the beat of a heart.","TWN":"那光芒雖小，卻像心跳一樣有規律地閃爍著……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"빛을 에워싸듯, 수많은 우주 함대가 벌떼처럼 날아다니며 탐사선을 요격해 댔지.","JPN":"光を囲むように、たくさんの宇宙艦隊が飛び回りながら探査船を迎撃してきた。","ENG":"And surrounding that light, space fleets swarmed like wasps, intercepting our expedition ship before it got close.","TWN":"就像被光包圍一樣，無數的宇宙艦隊像蜂群一樣飛來飛去，攔截探測船。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리는 녀석들에게 속수무책으로 당할 수밖에 없었어.","JPN":"私たちはやつらにやられっぱなしだった。","ENG":"We didn't stand a chance.","TWN":"我們只能被那些傢伙牽著鼻子走。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"애초부터 우리가 타고 있던 탐사선에는 무기 같은 건 실려 있지 않았으니까.","JPN":"そもそも私たちの探査船に武器なんか積んでなかったからな。","ENG":"Our ship didn't even have weapons to begin with.","TWN":"本來我們乘坐的探險船上就沒有裝載武器之類的東西。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 그래서 어떻게 됐지?","JPN":"そうか。そこからは、どうなった？","ENG":"I see... So what happened next?","TWN":"原來如此。所以後來怎麼樣了？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어떻게 됐기는? 앞선 탐사조가 죽어 나자빠지는 사이에 탐사선을 돌렸지.","JPN":"どうもなにも。先鋒の探査組が死んでいくのを見て、急いで舵を切ったよ。","ENG":"What happened was... while the first team was getting wiped out, we turned the ship around!","TWN":"怎麼回事？在前面的探險隊死掉的時候，我把探險船調轉了方向。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"누군가는 살아남아야 거기서 본 걸 위에 보고하든, 말든 할 거 아니야?","JPN":"そこで見たことを報告するためには、誰かは生きて帰らないといけないだろう？","ENG":"Someone had to make it out alive and report what we saw out there.","TWN":"總得有人活下來，把看到的東西報告上去，不是嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그렇게 간신히 궤도를 빠져나간 순간, 나는 달에서부터 어떤 소리를 들었어.","JPN":"なんとかして軌道を抜け出た瞬間、月から何かが聞こえてきた。","ENG":"And just as we barely escaped orbit, I heard something from the moon.","TWN":"就在勉強脫離軌道的那一刻，我聽到了來自月球的某種聲音。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 그건… 틀림없이 누군가의 목소리였어…….","JPN":"それは……間違いなく、誰かの声だった……","ENG":"It was... definitely someone's voice...","TWN":"而且那……無疑是某人的聲音……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"달에서부터 목소리를 들었다고?","JPN":"月から声が聞こえてきた？","ENG":"You heard a voice from the moon?","TWN":"你說你從月亮上聽到了聲音？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이상하군. 우주에는 소리를 전달할 대기가 없을 텐데?","JPN":"妙だな。宇宙には音を伝える大気がないはずだが。","ENG":"That's strange. There's no atmosphere in space, so sound can't travel.","TWN":"奇怪了，宇宙中應該沒有傳遞聲音的空氣吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"알고 있어. 처음에는 그냥 웅웅거리길래, 탐사선의 노이즈인 줄 알고 무시했지.","JPN":"わかってる。最初はブンブンするだけで、探査船のノイズだと思ったよ。","ENG":"I know. At first, it was just this low humming, so I figured it was just static from the ship.","TWN":"我知道。一開始只是嗡嗡作響，我還以為是探測船的噪音，就沒在意。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하지만 아니었어.","JPN":"でも違った。","ENG":"But it wasn't.","TWN":"但不是這樣。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이내 그 목소리는 내 머릿속에 직접 속삭이기 시작했으니까.","JPN":"その声は、私の脳内に直接話しかけてきたんだ。","ENG":"Before long, that voice started whispering directly inside my head.","TWN":"接著那個聲音開始直接在我腦海中低語。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"틀림없이 들었어…….","JPN":"はっきりと聞いた……","ENG":"I heard it very clearly...","TWN":"我肯定聽到了……"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내 목소리가 들리냐고. 당신은 누구냐고.","JPN":"自分の声が聞こえているかって、あなたは誰かって。","ENG":"\\"Can you hear me?\\" it asked. \\"Who are you?\\"","TWN":"能聽見我說話嗎？你是誰？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"목소리가 들리면, 대답해 달라고…….","JPN":"声が聞こえているなら、答えてほしいって……","ENG":"\\"If you can hear me... please answer.\\"","TWN":"聽到聲音的話，請回答……"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……젠장.","JPN":"……くそ。","ENG":"...Shucks.","TWN":"……該死。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"달의 뒷면을 지키고 있을 마더 쉽이 어째서 지구에 나타났는지는 모르겠지만…….","JPN":"月の裏側を守っているはずのマザーシップが地球に現れた理由は知らないけど……","ENG":"I don't know why the mothership guarding the dark side of the moon showed up on Earth...","TWN":"雖然不知道守護月球背面的母艦為什麼會出現在地球上……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 나타난 이상, 북방합의체 녀석들은 기를 쓰고 날 찾으려 들겠지.","JPN":"あれが現れた以上、北方合意体のやつらはどんな手を使ってでも私を探し出そうとするはずだ。","ENG":"But now that it has, the Northern Union will stop at nothing to hunt me down.","TWN":"那個出現了之後，北方和議會的傢伙們肯定會拼命找我的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>곱슬머리</color>.","JPN":"<color=#ffd34c>縮れ毛</color>。","ENG":"<color=#ffd34c>Curly hair</color>.","TWN":"<color=#ffd34c>自然捲</color>。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"탐사 때 쓰던 호출부호, 맞지?","JPN":"探査の時に使っていたコードネーム、よね？","ENG":"That was your code name during the exploration, was it not?","TWN":"這是探索時使用的行動代號，對吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"네 정체를 알고 있다. 함께 가 줘야겠어.","JPN":"君の正体は知っている。一緒に来てもらうわ。","ENG":"I know who you are. You are coming with me.","TWN":"我知道你是誰，跟我走一趟吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"게다가 녀석들은 리그 진행 중에도 날 습격해 왔어.","JPN":"しかもやつらはリーグの途中からも私を襲ってきた。","ENG":"They even attacked me while the league was still going on.","TWN":"而且那些傢伙在聯賽進行中也襲擊了我。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이곳의 위치는 이미 녀석들에게 노출되어 있다고 생각해도 무관하겠지.","JPN":"こっちの居場所はもうバレてると思った方がいい。","ENG":"I think it's fair to assume they already know this location.","TWN":"即使認為這個地方的位置已經暴露給那些傢伙也無妨。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그렇다면 문제는 타이밍인데…….","JPN":"となると問題はタイミングなんだけど……","ENG":"Which means... timing is everything.","TWN":"那麼問題就是時機……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"무엇보다도 나는 지금 혼자가 아니야.","JPN":"何より、今私は1人じゃない。","ENG":"More importantly, I'm not alone right now.","TWN":"最重要的是，我現在不是一個人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"녀석들과 트러블이 발생한다면, 펠리세트나 스키너까지 휘말릴 가능성이 있어.","JPN":"やつらと一悶着起こせば、フェリセットやスキナーまで巻き込まれる可能性がある。","ENG":"If things go south, Félicette and Skinner could get caught in the crossfire.","TWN":"如果和那些傢伙發生衝突，費莉塞特和史金納也可能會被捲入其中。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내가 녀석들에게 끌려가는 한이 있더라도, 그것만큼은 피해야 해.","JPN":"私がやつらに連れていかれることになっても、それだけは防がないと。","ENG":"Even if I end up being taken, I can't let them get dragged into this.","TWN":"即使我被他們抓走，也絕不能讓那件事發生。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"일단은 코치에게 신변 보호 요청을 해야 하나?","JPN":"ひとまず身の安全のためにも、コーチに保護を要請するべきか？","ENG":"Maybe I should ask Coach for protection, at least for now?","TWN":"要不要先請求教練保護我？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아, 이럴 줄 알았다면 로터스 지부에 남아 있는 게 더 안전했을 지도 모르는데……","JPN":"はあ、こうなるとわかっていたら、いっそロータス支部に残るほうが安全だったかもな……","ENG":"*Sigh* If I'd known it would come to this, maybe staying at the Lotus Branch would've been safer...","TWN":"哈啊，早知道會這樣，留在洛德斯分部可能更安全……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"으음!?","JPN":"うん！？","ENG":"Hmm?!","TWN":"嗯？！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"거기 누구야……!?","JPN":"そこ、誰だ……！？","ENG":"Who's there...?!","TWN":"誰在那裡……？！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"녹색 머리 여자. 제법 감이 날카롭군.","JPN":"緑ノ髪ノ女。ナカナカ鋭イ。","ENG":"Green-haired woman. You've got good instincts.","TWN":"綠色頭髮的女人。感覺相當敏銳啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐, 너는……?","JPN":"あんたは……？","ENG":"Wait a second... you're...?","TWN":"等等，你……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그때, 눈밭에서 자해공갈 하던 침식체잖아……?","JPN":"あの時雪原で自害した侵食体……？","ENG":"You're that C.O. who staged that whole self-injury scam in the snow...?","TWN":"那時候，在雪地裡自殘的侵蝕體……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};